from abc import ABC, abstractmethod
from typing import Optional
from dataclasses import dataclass
from PySide6.QtCore import QThread, Signal, QObject


@dataclass
class RaceEvent:
    year: int
    round_number: int
    event_name: str
    country: str
    date: str
    event_type: str

    def to_dict(self) -> dict:
        return {
            "year": self.year,
            "round_number": self.round_number,
            "event_name": self.event_name,
            "country": self.country,
            "date": self.date,
            "type": self.event_type,
        }

    @classmethod
    def from_dict(cls, data: dict, year: int) -> 'RaceEvent':
        return cls(
            year=year,
            round_number=data.get("round_number", 0),
            event_name=data.get("event_name", ""),
            country=data.get("country", ""),
            date=data.get("date", ""),
            event_type=data.get("type", ""),
        )


class IRaceDataProvider(ABC):
    """Interface for race data providers."""

    @abstractmethod
    def get_events_by_year(self, year: int) -> list[dict]:
        """Get all events for a specific year."""
        pass

    @abstractmethod
    def get_events_by_years(self, years: list[int]) -> list[dict]:
        """Get events for multiple years."""
        pass


class RaceDataService(IRaceDataProvider):
    """Service for fetching race data from FastF1."""

    def __init__(self):
        self._cache: dict[int, list[dict]] = {}

    def get_events_by_year(self, year: int) -> list[dict]:
        if year in self._cache:
            return self._cache[year]

        from src.f1_data import get_race_weekends_by_year
        events = get_race_weekends_by_year(year)

        for event in events:
            event["year"] = year

        self._cache[year] = events
        return events

    def get_events_by_years(self, years: list[int]) -> list[dict]:
        all_events = []
        for year in years:
            events = self.get_events_by_year(year)
            all_events.extend(events)
        return all_events

    def clear_cache(self, year: Optional[int] = None) -> None:
        if year:
            self._cache.pop(year, None)
        else:
            self._cache.clear()


class CachedRaceDataService(IRaceDataProvider):
    """Decorator that adds caching to any IRaceDataProvider."""

    def __init__(self, delegate: IRaceDataProvider):
        self._delegate = delegate
        self._year_cache: dict[int, list[dict]] = {}

    def get_events_by_year(self, year: int) -> list[dict]:
        if year not in self._year_cache:
            self._year_cache[year] = self._delegate.get_events_by_year(year)
        return self._year_cache[year]

    def get_events_by_years(self, years: list[int]) -> list[dict]:
        all_events = []
        for year in years:
            all_events.extend(self.get_events_by_year(year))
        return all_events

    def invalidate_cache(self, year: Optional[int] = None) -> None:
        if year:
            self._year_cache.pop(year, None)
        else:
            self._year_cache.clear()


class FetchMultiYearWorker(QThread):
    """Worker thread for fetching data across multiple years."""

    result = Signal(list)
    progress = Signal(int, int)  # current, total
    error = Signal(str)

    def __init__(self, years: list[int], service: IRaceDataProvider, parent=None):
        super().__init__(parent)
        self.years = years
        self.service = service

    def run(self):
        try:
            from src.f1_data import enable_cache
            enable_cache()
        except Exception:
            pass

        try:
            all_events = []
            total = len(self.years)

            for idx, year in enumerate(self.years):
                events = self.service.get_events_by_year(year)
                all_events.extend(events)
                self.progress.emit(idx + 1, total)

            self.result.emit(all_events)
        except Exception as e:
            self.error.emit(str(e))


class RaceDataServiceFactory:
    """Factory for creating RaceDataService instances."""

    _instance: Optional[RaceDataService] = None

    @classmethod
    def get_shared_instance(cls) -> RaceDataService:
        """Get a shared singleton instance of RaceDataService."""
        if cls._instance is None:
            cls._instance = RaceDataService()
        return cls._instance

    @classmethod
    def create(cls) -> RaceDataService:
        """Create a new RaceDataService instance."""
        return RaceDataService()

    @classmethod
    def create_cached(cls, base_service: Optional[IRaceDataProvider] = None) -> CachedRaceDataService:
        """Create a cached service wrapper."""
        delegate = base_service or cls.get_shared_instance()
        return CachedRaceDataService(delegate)
